boot.artifact:
// inferred-not-tested:artifact H0 探针未闭合；纯 ESM、无 DOM
import { DateTime } from 'https://cdn.jsdelivr.net/npm/luxon@3/+esm';
const source = DateTime.fromISO(data.local_iso, { zone: data.from_zone,
  locale: data.locale });
if (!source.isValid) throw new Error(source.invalidExplanation);
const target = source.setZone(data.to_zone);
const result = { iso: target.toISO(), zone: target.zoneName, offset_minutes: target.offset,
  possible_source_offsets: source.getPossibleOffsets().map(d => d.toISO()) };

